#!/usr/bin/env node
/**
 * Evidence generator — runs tt against a fresh, clock-pinned database and captures
 * verbatim output into acceptance/evidence/cli-transcript.md, organised by the §17
 * acceptance criteria. This is the "verbatim output" record for the PR; it is
 * regenerated by `npm run evidence` and checked in.
 *
 * Deterministic: TT_NOW pins the clock and the database is thrown away afterwards.
 */
process.removeAllListeners('warning');
process.on('warning', (w) => {
  if (w.name === 'ExperimentalWarning' && /SQLite/.test(w.message)) return;
  process.emitWarning(w);
});
import { spawnSync } from 'node:child_process';
import { mkdtempSync, rmSync, writeFileSync, mkdirSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { join, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';
import { Store } from '../packages/core/dist/index.js';
import {
  initCheckinState,
  evaluateCheckin,
  nominalCheckins,
} from '../packages/core/dist/index.js';

const ROOT = join(dirname(fileURLToPath(import.meta.url)), '..');
const BIN = join(ROOT, 'packages/cli/dist/bin.js');
const OUT = join(ROOT, 'acceptance/evidence/cli-transcript.md');

const dir = mkdtempSync(join(tmpdir(), 'stint-evidence-'));
const db = join(dir, 'tt.sqlite');
const NOW = '2026-06-24T17:30:00Z';

const md = [];
md.push('# Stint — acceptance evidence (verbatim CLI transcript)');
md.push('');
md.push(
  'Generated by `npm run evidence`. Every block below is the exact stdout/stderr and',
  'exit code of a `tt` command run against a fresh database with the clock pinned to',
  '`' + NOW + '` (so durations are reproducible). Sections map to the PRD §17',
  'acceptance criteria.',
);
md.push('');

function tt(args, now = NOW) {
  const res = spawnSync('node', [BIN, ...args], {
    encoding: 'utf8',
    env: { ...process.env, TT_DB: db, TT_NOW: now, NODE_NO_WARNINGS: '1' },
  });
  return { out: (res.stdout ?? '').trimEnd(), err: (res.stderr ?? '').trimEnd(), code: res.status ?? 0 };
}

function show(args, { now = NOW, note } = {}) {
  const r = tt(args, now);
  const cmd = 'tt ' + args.map((a) => (/\s/.test(a) ? JSON.stringify(a) : a)).join(' ');
  const lines = [];
  lines.push('```console');
  lines.push('$ ' + cmd + (now !== NOW ? `    # now = ${now}` : ''));
  if (r.out) lines.push(r.out);
  if (r.err) lines.push(...r.err.split('\n').map((l) => l));
  lines.push(`# exit ${r.code}`);
  lines.push('```');
  if (note) lines.push('', note);
  md.push(lines.join('\n'), '');
  return r;
}

function section(title, body) {
  md.push(`## ${title}`, '');
  if (body) md.push(body, '');
}

// ───────────────────────────── R1 + R2 ──────────────────────────────────────
section(
  'R1 / R2 — one open entry; surfaces never disagree',
  'A timer started through `tt` is the single open entry; starting another atomically closes the first.',
);
show(['start', 'auth refactor', '--client', 'Client A', '--project', 'API', '--tag', 'deep', '--at', '2026-06-24T09:00:00Z']);
show(['status'], { note: 'Derived elapsed = now − start, computed on demand (R1, R3).' });
show(['start', 'code review', '--client', 'Client A', '--at', '2026-06-24T16:00:00Z']);
show(['list', '--today', '--all'], { note: 'Exactly one entry is open (R2); the first was closed at 16:00.' });

// ───────────────────────────── R3 ───────────────────────────────────────────
section(
  'R3 — close / sleep / crash never corrupts elapsed',
  'Why it *cannot* corrupt: elapsed is never stored, only `start_utc` is, and that is ' +
    'written once under an atomic `BEGIN IMMEDIATE`. Each `tt` invocation below is a ' +
    'separate OS process that opens the database cold — so reading the running timer ' +
    'from a fresh process *is* the close-and-reopen (and stands in for a crash with no ' +
    'clean shutdown: no `end` was ever written, nothing is replayed on open). The ' +
    'stored `start_utc` is identical across reopens; only the derived elapsed grows. ' +
    'Adversarial kill-mid-write fault injection is the job of PROP + the MANUAL runbook; ' +
    'this transcript shows the structural reason there is nothing to recover.',
);
{
  const clockA = '2026-06-24T16:30:00Z';
  const clockB = '2026-06-24T17:30:00Z';
  const before = tt(['status', '--json'], clockA);
  const after = tt(['status', '--json'], clockB);
  const startOf = (j) => JSON.parse(j.out).entry.start_utc;
  const elapsedOf = (j) => JSON.parse(j.out).entry.elapsed_seconds;
  const wall = (Date.parse(clockB) - Date.parse(clockA)) / 1000;
  md.push(
    '```text',
    '# Two independent `tt` processes open the same file at different clocks:',
    `process A (now ${clockA}): start_utc=${startOf(before)}  elapsed_seconds=${elapsedOf(before)}`,
    `process B (now ${clockB}): start_utc=${startOf(after)}  elapsed_seconds=${elapsedOf(after)}`,
    `stored start_utc unchanged across reopen: ${startOf(before) === startOf(after)}`,
    `elapsed is purely derived (now − start), not stored: ` +
      `${elapsedOf(after) - elapsedOf(before)}s of growth == ${wall}s of wall clock between the two reopens`,
    '```',
    '',
  );
}
show(['status'], { now: '2026-06-24T17:30:00Z', note: 'Human-readable view of that same reopened entry — elapsed grows purely from the wall clock.' });

// ───────────────────────────── R4 + R7 ──────────────────────────────────────
section('R4 / R7 — rounding never mutates stored time; reports group, filter, round, export');
show(['stop', '--at', '2026-06-24T16:25:00Z']);
show(['report', '--today', '--all'], { note: 'Exact stored totals — rounding is off by default (R4).' });
show(['report', '--today', '--all', '--round', '15'], { note: 'Rounding applies only to the grouped line, nearest 15 min; stored times are untouched.' });
show(['export', '--today', '--csv'], { note: 'CSV export — the exact §09 R6 column contract (R7).' });
show(['report', '--today', '--by', 'tag', '--all'], { note: 'Grouping by tag (R7).' });

// ───────────────────────────── R5 ───────────────────────────────────────────
section('R5 — sleep yields a flagged entry, second-accurate spans, reversible subtract');
{
  // Inject a real suspend→resume cycle through the shared core (as powerMonitor would).
  const store = Store.open({ path: db, clock: () => new Date(NOW) });
  const open = store.listEntries().find((e) => e.description === 'code review');
  store.recordSleepSpan(open.id, '2026-06-24T16:05:00Z', '2026-06-24T16:11:30Z', 'event');
  store.close();
  md.push('_A 6m30s suspend→resume cycle was recorded on entry ' + open.id + ' (as `powerMonitor` would on a real machine)._', '');
}
show(['sleep', 'ls'], { note: 'The entry is flagged slept-through with a second-accurate span.' });
show(['sleep', 'subtract', '2'], { note: 'Subtract moves exactly the slept seconds into excluded; billable drops, raw is unchanged (R5).' });
show(['sleep', 'subtract', '2'], { note: 'Reversible — running it again restores the prior excluded_seconds.' });

// ───────────────────────────── R6 ───────────────────────────────────────────
section('R6 — check-in cadence: first at 60 min, then 30, autonomous, survives relaunch, realigns from wake');
{
  const start = '2026-06-24T09:00:00Z';
  const grid = nominalCheckins(start, 60, 30, start, '2026-06-24T12:00:00Z');
  let s = initCheckinState(start, 60);
  const at = (m) => new Date(Date.parse(start) + m * 60000);
  const fireAt60 = evaluateCheckin(s, 30, at(60));
  s = fireAt60.state;
  // Long sleep: wake at 300 min collapses the backlog to a single fire.
  const afterSleep = evaluateCheckin(s, 30, at(300));
  const lines = [
    '```text',
    'nominal grid (start 09:00, first 60m, then 30m):',
    ...grid.map((g) => '  ' + g),
    '',
    `first check-in fires at start+60 → ${fireAt60.fire ? 'FIRES' : 'no'} (next due ${fireAt60.state.nextDueUtc})`,
    `after a long sleep, wake at +300m → ${afterSleep.fire ? 'FIRES ONCE' : 'no'}, ` +
      `collapsed ${afterSleep.collapsedBacklog} missed slots, realigns to ${afterSleep.state.nextDueUtc}`,
    '```',
  ];
  md.push(lines.join('\n'), '', '_Computed from `@stint/core`’s pure cadence logic; the long-form real-time run is in the MANUAL runbook._', '');
}

// ───────────────────────────── R8 ───────────────────────────────────────────
section('R8 — every GUI capability is reachable from tt');
show(['client', 'ls'], { note: 'Reference-data management is a CLI surface too.' });
md.push(
  'The full GUI↔CLI capability matrix is `acceptance/parity-matrix.json`, asserted complete by',
  '`packages/gui/test/parity.test.ts` (each GUI IPC channel maps to a real `tt` command).',
  '',
);

// ───────────────────────────── R9 ───────────────────────────────────────────
section('R9 — no network connections');
{
  const res = spawnSync('node', [join(ROOT, 'scripts/check-no-network.mjs')], { encoding: 'utf8' });
  md.push('```console', '$ npm run verify:no-network', (res.stdout ?? '').trimEnd(), `# exit ${res.status ?? 0}`, '```', '');
}

// ───────────────────────────── machine contract ─────────────────────────────
section('Machine contract — `--json` everywhere, clean exit codes');
show(['status', '--json']);
show(['rm', '99'], { note: 'Refusal without --force exits non-zero on stderr.' });

mkdirSync(dirname(OUT), { recursive: true });
writeFileSync(OUT, md.join('\n').replace(/\n{3,}/g, '\n\n').trimEnd() + '\n');
rmSync(dir, { recursive: true, force: true });
console.log(`wrote ${OUT}`);
